import turfBearing from '@turf/bearing';
import turfDestination from '@turf/destination';
import turfDistance from '@turf/distance';
import { lineString as turfLineString } from '@turf/helpers';
import turfLineDistance from '@turf/length';
import turfLineArc from '@turf/line-arc';
import turfMidpoint from '@turf/midpoint';
import {
  toMercator as turfToMercator,
  toWgs84 as turfToWgs84,
} from '@turf/projection';
import type GeoJSON from 'geojson';

import type { FeatureProperties } from '../../../types/connection-layer.js';
import type { Location } from '../../../types/location.js';

const getArcFeatureItem = (
  coordinates: GeoJSON.Position[],
): GeoJSON.Feature<GeoJSON.LineString> => {
  const feature = turfLineString(coordinates);

  const parsedLineString = turfToWgs84(feature);

  const {
    geometry: {
      coordinates: [start, end],
    },
  } = parsedLineString;

  const lineDistance = turfLineDistance(parsedLineString);
  const midPoint = turfMidpoint(start, end);
  const bearing = turfBearing(start, end) - 90;
  const center = turfDestination(midPoint, lineDistance, bearing);

  const lineArc = turfLineArc(
    center,
    turfDistance(center, start),
    turfBearing(center, end),
    turfBearing(center, start),
    { steps: 256 },
  );

  return turfToMercator(lineArc);
};

export const getArcLineFeature = (
  path: Location[],
  featureProperties: FeatureProperties,
): GeoJSON.Feature<GeoJSON.LineString> => {
  const finalCoordinates: GeoJSON.Position[] = [];

  for (let i = 0; i < path.length - 1; i++) {
    const start = path[i];
    const end = path[i + 1];

    const coordinates: GeoJSON.Position[] = [
      [start.longitude, start.latitude],
      [end.longitude, end.latitude],
    ];

    const feature = getArcFeatureItem(coordinates);

    finalCoordinates.push(...feature.geometry.coordinates.reverse());
  }

  return turfLineString(finalCoordinates, {
    ...featureProperties,
  });
};
